# art_coordination_tracker.py — track ART coordination event health

from dataclasses import dataclass, field
from typing import List, Dict, Optional
from datetime import date

@dataclass
class Blocker:
    sprint: int
    team: str
    description: str
    blocker_type: str  # "within_art" | "outside_art" | "technical" | "dependency"
    raised_date: date
    resolved_date: Optional[date] = None

    @property
    def is_open(self) -> bool:
        return self.resolved_date is None

    @property
    def age_days(self) -> int:
        if self.resolved_date:
            return (self.resolved_date - self.raised_date).days
        return (date.today() - self.raised_date).days

@dataclass
class ARTSyncRecord:
    sprint: int
    date: date
    teams_present: List[str]
    blockers_raised: List[Blocker] = field(default_factory=list)
    model_performance_trend: str = "stable"  # improving | stable | degrading

@dataclass
class SystemDemoRecord:
    sprint: int
    date: date
    integrated_capabilities_demonstrated: List[str]
    stakeholders_attended: int
    integration_issues_found: int
    integration_issues_description: List[str] = field(default_factory=list)

def analyse_art_health(
    syncs: List[ARTSyncRecord],
    demos: List[SystemDemoRecord]
) -> Dict[str, object]:
    all_blockers = [b for s in syncs for b in s.blockers_raised]
    open_blockers = [b for b in all_blockers if b.is_open]
    resolved = [b for b in all_blockers if not b.is_open]

    avg_resolution_days = (
        sum(b.age_days for b in resolved) / len(resolved) if resolved else 0
    )

    blocker_by_team = {}
    for b in all_blockers:
        if b.team not in blocker_by_team:
            blocker_by_team[b.team] = 0
        blocker_by_team[b.team] += 1

    integration_issues_per_demo = (
        sum(d.integration_issues_found for d in demos) / len(demos) if demos else 0
    )

    model_trend_counts = {}
    for s in syncs:
        model_trend_counts[s.model_performance_trend] = (
            model_trend_counts.get(s.model_performance_trend, 0) + 1
        )

    return {
        "total_blockers": len(all_blockers),
        "open_blockers": len(open_blockers),
        "avg_resolution_days": round(avg_resolution_days, 1),
        "blocker_concentration": blocker_by_team,
        "avg_integration_issues_per_demo": round(integration_issues_per_demo, 1),
        "model_performance_trends": model_trend_counts,
    }

# model_governance_council.py — coordinate model versioning across ART teams

from dataclasses import dataclass, field
from typing import List, Optional, Dict
from datetime import date

@dataclass
class ModelVersionRequirement:
    team: str
    minimum_version: str
    maximum_version: Optional[str]  # None = no upper bound
    reason: str
    sprint_constraint_end: Optional[date] = None  # None = permanent requirement

@dataclass
class ModelUpdateProposal:
    proposed_version: str
    proposed_date: date
    changes: List[str]
    performance_delta: Dict[str, float]  # metric -> delta (positive = improvement)
    platform_team_rationale: str

    def meets_requirement(self, req: ModelVersionRequirement) -> bool:
        from packaging import version
        proposed = version.parse(self.proposed_version)
        min_req = version.parse(req.minimum_version)
        if proposed < min_req:
            return False
        if req.maximum_version:
            max_req = version.parse(req.maximum_version)
            if proposed > max_req:
                return False
        return True

def assess_update_compatibility(
    proposal: ModelUpdateProposal,
    team_requirements: List[ModelVersionRequirement]
) -> dict:
    conflicts = []
    compatible = []
    for req in team_requirements:
        try:
            if proposal.meets_requirement(req):
                compatible.append(req.team)
            else:
                conflicts.append({
                    "team": req.team,
                    "reason": req.reason,
                    "constraint": f">= {req.minimum_version}"
                    + (f", <= {req.maximum_version}" if req.maximum_version else ""),
                })
        except Exception:
            # packaging not available; simple string comparison
            conflicts.append({"team": req.team, "reason": "version comparison failed"})
    return {
        "proposed_version": proposal.proposed_version,
        "compatible_teams": compatible,
        "conflicting_teams": conflicts,
        "can_proceed": len(conflicts) == 0,
    }
